def parse_pdf_invoice_upload(self, payload: dict) -> str:
    """Extract text from an uploaded invoice PDF task."""
    file_path = self._get_upload_path(payload)
    try:
        from pypdf import PdfReader
    except ImportError as exc:
        raise RuntimeError(
            "PDF processing requires the pypdf package. Install it before processing invoice PDFs."
        ) from exc

    reader = PdfReader(str(file_path))
    page_text = []
    for page_number, page in enumerate(reader.pages, start=1):
        text = page.extract_text() or ""
        page_text.append(f"--- Page {page_number} ---\n{text.strip()}")

    return self._format_uploaded_document(
        "INVOICE PDF",
        payload,
        "\n\n".join(page_text).strip() or "[No extractable PDF text found]",
    )

def parse_csv_upload(self, payload: dict) -> str:
    """Parse an uploaded CSV task into text for the agent."""
    file_path = self._get_upload_path(payload)
    raw_text = file_path.read_text(encoding="utf-8-sig")
    reader = csv.DictReader(StringIO(raw_text))

    if reader.fieldnames:
        rows = []
        for row_number, row in enumerate(reader, start=1):
            values = ", ".join(f"{key}: {value}" for key, value in row.items())
            rows.append(f"Row {row_number}: {values}")
        content = f"Columns: {', '.join(reader.fieldnames)}\n" + "\n".join(rows)
    else:
        content = raw_text

    return self._format_uploaded_document("CSV FILE", payload, content.strip())

